import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerVentas } from '../services/ventaService';

const Reportes = () => {
    const navigate = useNavigate();
    const [ventas, setVentas] = useState([]);
    const [filtro, setFiltro] = useState('dia');
    const [busquedaFecha, setBusquedaFecha] = useState(new Date().toISOString().split('T')[0]);

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            cargarVentas();
        }
    }, [navigate, filtro, busquedaFecha]);

    const cargarVentas = async () => {
        const data = await obtenerVentas();
        if (!data) return;

        const fechaRef = new Date(busquedaFecha + "T12:00:00"); // Mediodía evita problemas de timezone

        const filtradas = data.filter(v => {
            // ✅ Maneja tanto string ISO como array de Java
            const fechaV = new Date(
                Array.isArray(v.fechaVenta)
                    ? `${v.fechaVenta[0]}-${String(v.fechaVenta[1]).padStart(2,'0')}-${String(v.fechaVenta[2]).padStart(2,'0')}T${String(v.fechaVenta[3]).padStart(2,'0')}:${String(v.fechaVenta[4]).padStart(2,'0')}:00`
                    : v.fechaVenta
            );

            if (filtro === 'dia') {
                return (
                    fechaV.getDate() === fechaRef.getDate() &&
                    fechaV.getMonth() === fechaRef.getMonth() &&
                    fechaV.getFullYear() === fechaRef.getFullYear()
                );
            } else if (filtro === 'mes') {
                return (
                    fechaV.getMonth() === fechaRef.getMonth() &&
                    fechaV.getFullYear() === fechaRef.getFullYear()
                );
            } else {
                return fechaV.getFullYear() === fechaRef.getFullYear();
            }
        });

        setVentas(filtradas);
    };

    const totalVendido = ventas.reduce((acc, v) => acc + (v.total || 0), 0);
    const totalGastos = ventas.reduce((acc, v) => acc + ((v.precioCompra || 0) * (v.cantidad || 0)), 0);
    const gananciaNeta = totalVendido - totalGastos;

    // ✅ Función para formatear la fecha sin importar el formato que mande el backend
    const formatearFecha = (fechaVenta) => {
        try {
            if (Array.isArray(fechaVenta)) {
                return `${String(fechaVenta[3]).padStart(2,'0')}:${String(fechaVenta[4]).padStart(2,'0')}`;
            }
            return new Date(fechaVenta).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
        } catch {
            return '--:--';
        }
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '1200px', margin: '0 auto' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '20px' }}>
                <button onClick={() => navigate("/inventario")} style={{ backgroundColor: '#6c757d', color: 'white', padding: '10px 15px', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>⬅️ Volver al Inventario</button>
                <h2 style={{ color: '#007bff', margin: 0 }}>📈 Reporte Financiero</h2>
            </div>

            {/* FILTROS */}
            <div style={{ display: 'flex', gap: '20px', background: '#ffffff', padding: '25px', borderRadius: '15px', marginBottom: '25px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', alignItems: 'flex-end' }}>
                <div style={{ flex: 1 }}>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>Tipo de Filtro:</label>
                    <select value={filtro} onChange={(e) => setFiltro(e.target.value)} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '15px' }}>
                        <option value="dia">Vista Diaria</option>
                        <option value="mes">Vista Mensual</option>
                        <option value="año">Vista Anual</option>
                    </select>
                </div>
                <div style={{ flex: 1 }}>
                    <label style={{ display: 'block', marginBottom: '8px', fontWeight: 'bold' }}>Fecha de Referencia:</label>
                    <input type="date" value={busquedaFecha} onChange={(e) => setBusquedaFecha(e.target.value)} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '15px' }} />
                </div>
                <button onClick={cargarVentas} style={{ backgroundColor: '#007bff', color: 'white', padding: '12px 25px', border: 'none', borderRadius: '8px', cursor: 'pointer', fontWeight: 'bold' }}>
                    🔄 Sincronizar
                </button>
            </div>

            {/* INDICADORES */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginBottom: '30px' }}>
                <div style={{ background: '#f8f9fa', padding: '25px', borderRadius: '15px', borderLeft: '5px solid #007bff', textAlign: 'center' }}>
                    <span style={{ color: '#666', fontSize: '14px', textTransform: 'uppercase' }}>Ingresos Brutos</span>
                    <h2 style={{ margin: '10px 0 0 0', color: '#007bff' }}>${totalVendido.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
                <div style={{ background: '#f8f9fa', padding: '25px', borderRadius: '15px', borderLeft: '5px solid #dc3545', textAlign: 'center' }}>
                    <span style={{ color: '#666', fontSize: '14px', textTransform: 'uppercase' }}>Costo de Inversión</span>
                    <h2 style={{ margin: '10px 0 0 0', color: '#dc3545' }}>${totalGastos.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
                <div style={{ background: '#e8f5e9', padding: '25px', borderRadius: '15px', borderLeft: '5px solid #28a745', textAlign: 'center' }}>
                    <span style={{ color: '#2e7d32', fontSize: '14px', textTransform: 'uppercase' }}>Utilidad Neta</span>
                    <h2 style={{ margin: '10px 0 0 0', color: '#28a745' }}>${gananciaNeta.toLocaleString('es-MX', { minimumFractionDigits: 2 })}</h2>
                </div>
            </div>

            {/* TABLA */}
            <div style={{ background: 'white', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
                <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead style={{ background: '#343a40', color: 'white' }}>
                        <tr>
                            <th style={{ padding: '15px' }}>Hora</th>
                            <th>Producto</th>
                            <th>Cant.</th>
                            <th>Vendedor</th>
                            <th>Venta</th>
                            <th>Utilidad</th>
                        </tr>
                    </thead>
                    <tbody>
                        {ventas.length > 0 ? ventas.map((v, i) => (
                            <tr key={i} style={{ borderBottom: '1px solid #eee', textAlign: 'center' }}>
                                <td style={{ padding: '12px' }}>{formatearFecha(v.fechaVenta)}</td>
                                <td style={{ textAlign: 'left', paddingLeft: '15px' }}>{v.nombreProducto}</td>
                                <td>{v.cantidad}</td>
                                <td><mark style={{ background: '#e7f3ff', padding: '2px 8px', borderRadius: '4px' }}>{v.vendedorMatricula}</mark></td>
                                <td style={{ fontWeight: 'bold' }}>${(v.total || 0).toFixed(2)}</td>
                                <td style={{ color: '#28a745', fontWeight: 'bold' }}>
                                    +${((v.total || 0) - ((v.precioCompra || 0) * (v.cantidad || 0))).toFixed(2)}
                                </td>
                            </tr>
                        )) : (
                            <tr><td colSpan="6" style={{ padding: '40px', color: '#999', textAlign: 'center' }}>No hay registros para este periodo.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Reportes;
